const defaultCreditDataTableSettings: Partial<DataTableParams> = {
  isSelectMode: false,
  isDeleteMode: false,
  isAddMode: false,
  isForceShowTable: false,
  isEditedMode: false,
  isScrollable: false,
  isFuzzySearchMode: false,
  isColSelectorMode: false,
  isSortMode: false,
  noDataConText: '',
};

export class CreditDataTable<T> {
  data: Array<T> = new Array<T>();
  tableCols: Array<CreditTableCol> = new Array<CreditTableCol>();
  tableSettings: Partial<DataTableParams> = null;
  tableCleanSelection: boolean = false;

  init(
    tableCols: Array<CreditTableCol>,
    initialData: Array<T> | null = null,
    settings: Partial<DataTableParams> = {}
  ) {
    this.data = initialData;
    this.tableCols = tableCols;
    this.tableSettings = {
      ...defaultCreditDataTableSettings,
      ...settings,
    };

    this.resetTableBatchData();
  }

  push(data: T) {
    this.data.push(data);
  }

  removeAt(index: number) {
    if (0 <= index && index < this.data.length) {
      this.data = this.data.filter((_, i) => index !== i);
    }
  }

  resetTableBatchData() {
    this.tableCleanSelection = true;
    setTimeout(() => {
      this.tableCleanSelection = false;
    });
  }
}
