import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { CreditDataTable, CustAppSegmentDetail } from '../../credit.model';

@Component({
  selector: 'credit-form-cust-app-segment-template',
  templateUrl: './form-cust-app-segment-template.component.html',
  styleUrls: ['./form-cust-app-segment-template.component.scss'],
})
export class FormCustAppSegmentTemplateComponent implements OnInit {
  custAppSegmentDetailDataTable: CreditDataTable<CustAppSegmentDetail> =
    new CreditDataTable();

  constructor(public route: ActivatedRoute) {}

  ngOnInit(): void {
    this.initCustAppSegmentDetailTable();
  }

  initCustAppSegmentDetailTable() {
    this.custAppSegmentDetailDataTable.init(
      [
        { label: 'Seq', field: 'seq', class: 'flex-0' },
        {
          label: '客戶產品分類明細',
          field: 'custAppSegmentDetail',
        },
        { label: '主要', field: 'primaryFlag', class: 'flex-0' },
        { label: '%', field: 'percent', class: 'flex-0' },
        { label: 'Active', field: 'active', class: 'flex-0' },
        { label: 'Remark', field: 'remark' },
        { label: '', field: 'delete', class: 'flex-0' },
      ],
      [
        {
          custAppSegmentDetail: '',
          primaryFlag: '',
          percent: '',
          active: '',
          remark: '',
          delete: '',
        },
      ]
    );
  }

  insertCustAppSegmentDetailRow() {
    const custAppSegmentDetailData = this.custAppSegmentDetailDataTable.data;

    this.custAppSegmentDetailDataTable.push({
      custAppSegmentDetail: '',
      primaryFlag: '',
      percent: '',
      active: '',
      remark: '',
      delete: '',
    });
  }

  removeCustAppSegmentDetailRow(index: number) {
    console.log('remove', index);
    this.custAppSegmentDetailDataTable.removeAt(index);
  }
}
