import { Component, OnInit } from '@angular/core';
import { CreditDataTable, Factoring } from '../../credit.model';

@Component({
  selector: 'credit-table-factoring-template',
  templateUrl: './table-factoring-template.component.html',
  styleUrls: ['./table-factoring-template.component.scss'],
})
export class TableFactoringTemplateComponent implements OnInit {
  factoringDataTable: CreditDataTable<Factoring> = new CreditDataTable();

  factoringActiveIndex: number = -1;

  constructor() {}

  ngOnInit(): void {
    this.initFactoringTable();
  }

  initFactoringTable() {
    this.factoringDataTable.init(
      [
        { label: 'Group', field: 'group' },
        { label: 'Company', field: 'company' },
        { label: 'OU ID', field: 'ouId' },
        { label: 'Cust No.', field: 'custNo' },
        { label: 'Cust Name', field: 'custName' },
        { label: 'Cust Eng Name', field: 'custEngName' },
        { label: 'Bank', field: 'bank' },
        { label: 'End Date', field: 'endDate' },
        { label: 'Total Credit Limit', field: 'totalCreditLimit' },
        { label: 'Utilized credit line', field: 'utilizedCreditLine' },
        { label: 'Credit Balance', field: 'creditBalance' },
      ],
      [
        {
          group: '',
          company: '',
          ouId: '',
          custNo: '',
          custName: '',
          custEngName: '',
          bank: '',
          endDate: '',
          totalCreditLimit: '',
          utilizedCreditLine: '',
          creditBalance: '',
        },
      ]
    );
  }
}
