import { NgModule } from '@angular/core';
import { RouterModule, Routes } from '@angular/router';
import { CreditApplyComponent } from './credit-apply/credit-apply.component';
import { CreditUpdateComponent } from './credit-update/credit-update.component';
import { MultiPaymentTermsComponent } from './multi-payment-terms/multi-payment-terms.component';
import { CreditTpComponent } from './credit-tp/credit-tp.component';

const routes: Routes = [
  {
    path: 'credit-apply',
    children: [
      {
        path: 'apply',
        component: CreditApplyComponent,
      },
      {
        path: 'readonly',
        component: CreditApplyComponent,
      },
      {
        path: 'approving',
        component: CreditApplyComponent,
      },
    ],
  },
  {
    path: 'credit-update',
    children: [
      {
        path: 'apply',
        component: CreditUpdateComponent,
      },
      {
        path: 'readonly',
        component: CreditUpdateComponent,
      },
      {
        path: 'approving',
        component: CreditUpdateComponent,
      },
    ],
  },
  {
    path: 'multi-payment-terms',
    children: [
      {
        path: 'apply',
        component: MultiPaymentTermsComponent,
      },
      {
        path: 'readonly',
        component: MultiPaymentTermsComponent,
      },
      {
        path: 'approving',
        component: MultiPaymentTermsComponent,
      },
    ],
  },
  {
    path: 'credit-tp',
    children: [
      {
        path: 'apply',
        component: CreditTpComponent,
      },
      {
        path: 'readonly',
        component: CreditTpComponent,
      },
      {
        path: 'approving',
        component: CreditTpComponent,
      },
    ],
  },
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule],
})
export class CreditRoutingModule {}
