import { Component, HostListener, OnDestroy, OnInit } from '@angular/core';
import { CREDIT_STATUS } from '../credit.const';
import { Subject, takeUntil } from 'rxjs';
import { ActivatedRoute } from '@angular/router';

@Component({
  selector: 'app-multi-payment-terms',
  templateUrl: './multi-payment-terms.component.html',
  styleUrls: ['./multi-payment-terms.component.scss'],
})
export class MultiPaymentTermsComponent implements OnInit, OnDestroy {
  CREDIT_STATUS = CREDIT_STATUS;

  unsubscribe$: Subject<void> = new Subject();

  viewpointWidth: number = 0;

  role: CREDIT_STATUS = CREDIT_STATUS.APPLY;

  constructor(public route: ActivatedRoute) {}

  ngOnInit(): void {
    this.detectUrl();
  }

  ngOnDestroy(): void {
    this.unsubscribe$.next();
    this.unsubscribe$.complete();
  }

  @HostListener('window:resize', ['$event'])
  onViewPointWatcher(event: { target: { innerWidth: number } }): void {
    this.viewpointWidth = event.target.innerWidth;
  }

  detectUrl() {
    this.route.params.pipe(takeUntil(this.unsubscribe$)).subscribe(() => {
      const path = this.route.snapshot.routeConfig.path;
      const statusList = [
        CREDIT_STATUS.APPLY,
        CREDIT_STATUS.APPROVING,
        CREDIT_STATUS.READONLY,
      ];

      statusList.forEach((status) => {
        this.role = path === status ? status : this.role;
      });
    });
  }
}
