import { Component, OnInit } from '@angular/core';
import { CreditDataTable, PaymentTerms } from '../../credit.model';
import { ActivatedRoute } from '@angular/router';

@Component({
  selector: 'credit-form-multi-payment-terms-template',
  templateUrl: './form-multi-payment-terms-template.component.html',
  styleUrls: ['./form-multi-payment-terms-template.component.scss'],
})
export class FormMultiPaymentTermsTemplateComponent implements OnInit {
  applyMethod: string = '';
  cancelDialog: boolean = false;

  paymentTermsApplyDataTable: CreditDataTable<PaymentTerms> =
    new CreditDataTable();

  constructor(public route: ActivatedRoute) {}

  ngOnInit(): void {
    this.initPaymentTermsTable();
  }

  initPaymentTermsTable() {
    this.paymentTermsApplyDataTable.init(
      [
        { label: 'Seq', field: 'seq' },
        { label: 'Company', field: 'company' },
        { label: 'Brand', field: 'brand' },
        { label: '', field: 'appliedPaymentTerms' },
        { label: 'Category', field: 'category' },
        { label: 'Customer', field: 'customer' },
        { label: 'Sales', field: 'sales' },
        { label: 'Credit Payment Terms', field: 'creditPaymentTerms' },
        { label: 'Payment Terms', field: 'paymentTerms' },
        { label: '', field: 'delete' },
        { label: '', field: 'usageStatus' },
      ],
      []
    );
  }

  insertPaymentTermsRow() {
    this.paymentTermsApplyDataTable.push({
      company: '',
      brand: '',
      appliedPaymentTerms: '',
      category: '',
      customer: '',
      sales: '',
      creditPaymentTerms: '',
      paymentTerms: '',
      usageStatus: '',
    });
  }

  removePaymentTermsRow(index: number) {
    this.paymentTermsApplyDataTable.removeAt(index);
  }
}
