import { Component, HostListener, OnDestroy, OnInit } from '@angular/core';
import { CREDIT_STATUS } from '../credit.const';
import { Subject, takeUntil } from 'rxjs';
import { CreditDataTable, CreditManagementEvaluation } from '../credit.model';
import { ActivatedRoute } from '@angular/router';

@Component({
  selector: 'app-credit-apply',
  templateUrl: './credit-apply.component.html',
  styleUrls: ['./credit-apply.component.scss'],
})
export class CreditApplyComponent implements OnInit, OnDestroy {
  CREDIT_STATUS = CREDIT_STATUS;

  unsubscribe$: Subject<void> = new Subject();

  viewpointWidth: number = 0;

  creditManagementEvaluationDataTable: CreditDataTable<CreditManagementEvaluation> =
    new CreditDataTable();

  formInfo = new Map();

  role: CREDIT_STATUS = CREDIT_STATUS.APPLY;

  constructor(public route: ActivatedRoute) {
    this.viewpointWidth = window.innerWidth;
  }

  ngOnInit(): void {
    this.initCreditManagementEvaluationTable();

    this.detectUrl();
  }

  ngOnDestroy(): void {
    this.unsubscribe$.next();
    this.unsubscribe$.complete();
  }

  @HostListener('window:resize', ['$event'])
  onViewPointWatcher(event: { target: { innerWidth: number } }): void {
    this.viewpointWidth = event.target.innerWidth;
  }

  detectUrl() {
    this.route.params.pipe(takeUntil(this.unsubscribe$)).subscribe(() => {
      const path = this.route.snapshot.routeConfig.path;
      const statusList = [
        CREDIT_STATUS.APPLY,
        CREDIT_STATUS.APPROVING,
        CREDIT_STATUS.READONLY,
      ];

      statusList.forEach((status) => {
        this.role = path === status ? status : this.role;
      });
    });
  }

  initCreditManagementEvaluationTable() {
    this.creditManagementEvaluationDataTable.init(
      [
        { label: '信管評價', field: 'evaluation' },
        { label: '執行人員', field: 'creditManagement' },
        { label: 'Date', field: 'date' },
      ],
      [
        {
          evaluation:
            'Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text Sameple Text',
          creditManagement: '1188(張家慧/Anne Chang)',
          date: '2023/8/1 下午 05:05:46',
        },
      ]
    );
  }
}
