import { Component, OnInit } from '@angular/core';
import { CreditDataTable, CreditStatus } from '../../credit.model';

@Component({
  selector: 'credit-table-credit-status-template',
  templateUrl: './table-credit-status-template.component.html',
  styleUrls: ['./table-credit-status-template.component.scss'],
})
export class TableCreditStatusTemplateComponent implements OnInit {
  creditStatusDataTable: CreditDataTable<CreditStatus> = new CreditDataTable();
  constructor() {}

  ngOnInit(): void {
    this.initCreditStatusTable();
  }

  initCreditStatusTable() {
    this.creditStatusDataTable.init(
      [
        { label: '', field: 'group' },
        { label: 'Credit', field: 'credit' },
        { label: 'Credit Balance', field: 'creditBalance' },
        { label: 'ExceedCredit', field: 'exceedCredit' },
        { label: 'Current AR', field: 'currentAR', class: 'positive' },
        { label: 'N/R', field: 'nr', class: 'positive' },
        { label: 'OVERDUE', field: 'overdue', class: 'positive' },
        {
          label: 'Pre-shipping Amt',
          field: 'preShippingAmt',
          class: 'positive',
        },
        { label: 'So Credit Amt', field: 'soCreditAmt', class: 'positive' },
        { label: 'Lend Out', field: 'lendOut', class: 'positive' },
        {
          label: 'L/C(Not be confirm)',
          field: 'lcNotBeConfirm',
          class: 'positive',
        },
        { label: 'Temp Amt', field: 'tempAmt', class: 'negative' },
        { label: 'BA Amt', field: 'baAmt', class: 'negative' },
        { label: 'Green Light', field: 'greenLight', class: 'negative' },
        { label: 'L/C(Be confirm)', field: 'lcBeConfirm', class: 'negative' },
      ],
      [
        {
          group: '',
          credit: '',
          creditBalance: '',
          exceedCredit: '',
          currentAR: '',
          nr: '',
          overdue: '',
          preShippingAmt: '',
          soCreditAmt: '',
          tempAmt: '',
          baAmt: '',
          greenLight: '',
          lendOut: '',
          lcBeConfirm: '',
          lcNotBeConfirm: '',
        },
      ]
    );
  }
}
