import { Component, OnInit } from '@angular/core';
import { ArInsurance, CreditDataTable } from '../../credit.model';

@Component({
  selector: 'credit-table-ar-insurance-template',
  templateUrl: './table-ar-insurance-template.component.html',
  styleUrls: ['./table-ar-insurance-template.component.scss'],
})
export class TableArInsuranceTemplateComponent implements OnInit {
  arInsuranceDataTable: CreditDataTable<ArInsurance> = new CreditDataTable();

  constructor() {}

  ngOnInit(): void {
    this.initArInsuranceTable();
  }

  initArInsuranceTable() {
    this.arInsuranceDataTable.init(
      [
        { label: '被保險人', field: 'insuredPerson' },
        { label: '保險公司', field: 'insuranceCompany' },
        { label: '有效期', field: 'insuredDateTo' },
        { label: '幣別', field: 'currency' },
        { label: '核准額度', field: 'approvedCreditLimit' },
        { label: '自負額(%)', field: 'indemnifyBurdenRate' },
        { label: 'Apply Issue', field: 'applyIssue' },
      ],
      [
        {
          insuredPerson: '',
          insuranceCompany: '',
          insuredDateTo: '',
          currency: '',
          approvedCreditLimit: '',
          indemnifyBurdenRate: '',
          applyIssue: '',
        },
      ]
    );
  }
}
