import { Component, OnInit } from '@angular/core';
import { CollateralDetail, CreditDataTable } from '../../credit.model';

@Component({
  selector: 'credit-table-collateral-detail-template',
  templateUrl: './table-collateral-detail-template.component.html',
  styleUrls: ['./table-collateral-detail-template.component.scss'],
})
export class TableCollateralDetailTemplateComponent implements OnInit {
  collateralDetailDataTable: CreditDataTable<CollateralDetail> =
    new CreditDataTable();

  constructor() {}

  ngOnInit(): void {
    this.initCollateralDetailTable();
  }

  initCollateralDetailTable() {
    this.collateralDetailDataTable.init(
      [
        { label: '質押單號', field: 'collateralNo' },
        { label: '日期', field: 'effectiveDateFrom' },
        { label: '代碼', field: 'custCode' },
        { label: '客戶名稱', field: 'custName' },
        { label: '質押項目', field: 'collateralItem' },
        { label: '保證人', field: 'guarantor' },
        { label: '保證對象', field: 'guarantee' },
        { label: '幣別', field: 'currency' },
        { label: '保證金額', field: 'guaranteeAmount' },
        { label: '有效日期', field: 'effectiveDateTo' },
        { label: '撤回日期', field: 'withdrawDate' },
        { label: '擔保品幣別', field: 'collateralCurrency' },
        { label: '擔保品市價', field: 'marketPrice' },
        { label: '擔保品備註', field: 'remark' },
      ],
      [
        {
          collateralNo: '',
          effectiveDateFrom: '',
          custCode: '',
          custName: '',
          collateralItem: '',
          guarantor: '',
          guarantee: '',
          currency: '',
          guaranteeAmount: '',
          effectiveDateTo: '',
          withdrawDate: '',
          collateralCurrency: '',
          marketPrice: '',
          remark: '',
        },
      ]
    );
  }
}
