import { Component, OnInit } from '@angular/core';
import { ArStatus, CreditDataTable } from '../../credit.model';

@Component({
  selector: 'credit-table-ar-status-template',
  templateUrl: './table-ar-status-template.component.html',
  styleUrls: ['./table-ar-status-template.component.scss'],
})
export class TableArStatusTemplateComponent implements OnInit {
  arStatusDataTable: CreditDataTable<ArStatus> = new CreditDataTable();

  constructor() {}

  ngOnInit(): void {
    this.initArStatusTable();
  }

  initArStatusTable() {
    this.arStatusDataTable.init(
      [
        { label: '', field: 'group' },
        { label: 'CURRENT', field: 'current' },
        { label: '1-7 Days', field: 'days1_7' },
        { label: '8-14 Days', field: 'days8_14' },
        { label: '15-30 Days', field: 'days15_30' },
        { label: '31-60 Days', field: 'days31_60' },
        { label: '61-90 Days', field: 'days61_90' },
        { label: '91-120 Days', field: 'days91_120' },
        { label: 'Over 120 Days', field: 'over120Days' },
      ],
      [
        {
          group: '',
          current: '',
          days1_7: '',
          days8_14: '',
          days15_30: '',
          days31_60: '',
          days61_90: '',
          days91_120: '',
          over120Days: '',
        },
      ]
    );
  }
}
